import {
  ArcRotateCamera, Scene, Engine, Vector3, Texture, Mesh, ParticleSystem, Color4, Color3, StandardMaterial, Matrix, Particle
} from '@babylonjs/core/Legacy/legacy';

export class SceneService {
  isMob: any = /iPad|iPhone|Android/g.test(navigator.userAgent);
  canvas: HTMLCanvasElement;
  scene: Scene;
  engine: Engine;
  camera: ArcRotateCamera;
  domeRadius = 300;

  constructor() {
    this.canvas = (document.getElementById('renderCanvas') as HTMLCanvasElement);
    this.engine = new Engine(this.canvas, true, { preserveDrawingBuffer: true, stencil: true }, true);
    this.init();
  }

  /** 初始化 */
  init() {
    if (Engine.isSupported()) {
      this.scene = this.createScene(this.engine);
      this.engine.enableOfflineSupport = false;
      if (this.isMob) {
        this.engine.setHardwareScalingLevel(0.5);
      } else {
        this.engine.setHardwareScalingLevel(1);
      }
      this.engine.runRenderLoop(() => {
        if (this.scene) {
          if (this.scene.activeCamera) {
            this.scene.render();
          }
        }
      });
    }
  }

  createScene(engine: Engine): Scene {
    const canvas = engine.getRenderingCanvas();
    const scene = new Scene(engine);
    scene.clearColor.set(0, 0, 0, 1);
    const camera1 = new ArcRotateCamera('Camera', -1.05, 1.4, 880, new Vector3(0, 15, 0), scene);
    camera1.attachControl(canvas, false);

    const ps = new ParticleSystem('particles', 2000, scene);
    ps.startPositionFunction = (worldMatrix: Matrix, positionToUpdate: Vector3) => {
      this.myStartPositionFunction(worldMatrix, positionToUpdate);
    };
    ps.particleTexture = new Texture('https://cdn.rawgit.com/wingnutt/misc/master/star.jpg', scene);
    ps.emitter = new Vector3(0, 15, 0);
    ps.minEmitBox = new Vector3(0, 0, 0); // Starting all from
    ps.maxEmitBox = new Vector3(0, 0, 0); // To...
    ps.color1 = ps.color2 = ps.colorDead = new Color4(1, 1, 1, 1);
    ps.minSize = 2;
    ps.maxSize = 5;
    ps.minLifeTime = 100.0;
    ps.maxLifeTime = 100.0;
    ps.emitRate = 5000;
    ps.blendMode = ParticleSystem.BLENDMODE_ONEONE;
    ps.minAngularSpeed = 0;
    ps.maxAngularSpeed = 0;
    ps.minEmitPower = 0;
    ps.maxEmitPower = 0;
    ps.updateSpeed = 0.005;
    ps.start();

    const box1 = Mesh.CreateBox('box1', 25, scene);
    const box2 = Mesh.CreateBox('box2', 25, scene);
    box1.material = new StandardMaterial('b1mat', scene);
    (box1.material as StandardMaterial).emissiveColor = Color3.Random();
    box2.material = new StandardMaterial('b2mat', scene);
    (box2.material as StandardMaterial).emissiveColor = Color3.Random();
    box2.parent = box1;
    box2.setPivotMatrix(Matrix.Translation(0, 340, 0));

    box1.rotation.x = .707;
    box1.rotation.y = .707;
    scene.beforeRender = () => {
      box1.rotation.z += .01;
    };
    return scene;
  }

  randomNumber(min: number, max: number) {
    return ((Math.random() * (max - min)) + min);
  }

  myStartPositionFunction(worldMatrix: Matrix, positionToUpdate: Vector3) {
    const v3 = this.getCart(this.domeRadius);
    Vector3.TransformCoordinatesFromFloatsToRef(v3.x, v3.y, v3.z, worldMatrix, positionToUpdate);
  }

  // https://rbrundritt.wordpress.com/2008/10/14/conversion-between-spherical-and-cartesian-coordinates-systems/
  getCart(radius: number) {
    const xy = [Math.random() * 2 * Math.PI, Math.acos(Math.random() * 2 - 1)];
    const lat = xy[0];
    const lon = xy[1];
    const x = radius * Math.cos(lat) * Math.cos(lon);
    const y = radius * Math.cos(lat) * Math.sin(lon);
    const z = radius * Math.sin(lat);
    return new Vector3(x, y, z);
  }

}
