import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';
import { ProjectComponent } from './page/project/project.component';
import { HomeComponent } from './page/home/home.component';
import { AboutComponent } from './page/about/about.component';
import { DetailsComponent } from './page/project/details/details.component';
import { TimelineComponent } from './page/timeline/timeline.component';
import { BlogComponent } from './page/blog/blog.component';
import { ArticleComponent } from './page/blog/article/article.component';

const routes: Routes = [
  { path: '', component: HomeComponent },
  { path: 'home', component: HomeComponent },
  { path: 'project', component: ProjectComponent },
  { path: 'projectdetails', component: DetailsComponent },
  { path: 'about', component: AboutComponent },
  { path: 'timeline', component: TimelineComponent },
  { path: 'blog', component: BlogComponent },
  { path: 'article', component: ArticleComponent },
];

@NgModule({
  imports: [
    RouterModule.forRoot(routes, {
      scrollPositionRestoration: 'enabled',
      anchorScrolling: 'enabled',
      scrollOffset: [0, 64]
    })
  ],
  exports: [RouterModule]
})
export class AppRoutingModule { }
